-- FUNÇÃO PARA VINCULAR DADOS À ORGANIZAÇÃO AUTOMATICAMENTE
CREATE OR REPLACE FUNCTION public.handle_new_data_organization()
RETURNS TRIGGER AS $$
BEGIN
  NEW.organization_id := (SELECT organization_id FROM public.profiles WHERE id = auth.uid());
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- GATILHOS (TRIGGERS) PARA TODAS AS TABELAS
DO $$
DECLARE
    t text;
BEGIN
    FOR t IN SELECT table_name FROM information_schema.tables WHERE table_schema = 'public' AND table_name NOT IN ('organizations', 'profiles')
    LOOP
        EXECUTE format('DROP TRIGGER IF EXISTS set_org_id_%I ON public.%I', t, t);
        EXECUTE format('CREATE TRIGGER set_org_id_%I BEFORE INSERT ON public.%I FOR EACH ROW EXECUTE FUNCTION public.handle_new_data_organization()', t, t);
    END LOOP;
END $$;

-- POLÍTICAS DE ISOLAMENTO (EXEMPLO PARA TODAS)
DO $$
DECLARE
    t text;
BEGIN
    FOR t IN SELECT table_name FROM information_schema.tables WHERE table_schema = 'public' AND table_name NOT IN ('organizations')
    LOOP
        EXECUTE format('DROP POLICY IF EXISTS "Org isolation" ON public.%I', t);
        EXECUTE format('CREATE POLICY "Org isolation" ON public.%I FOR ALL USING (organization_id = (SELECT organization_id FROM public.profiles WHERE id = auth.uid()))', t);
    END LOOP;
END $$;

DROP POLICY IF EXISTS "Leitura pública de organizações" ON public.organizations;
CREATE POLICY "Leitura pública de organizações" ON public.organizations FOR SELECT USING (true);
DROP POLICY IF EXISTS "Inserção pública de organizações" ON public.organizations;
CREATE POLICY "Inserção pública de organizações" ON public.organizations FOR INSERT WITH CHECK (true);
`;

// Helper to extract error message safely
const getErrorMessage = (error: any): string => {
    if (!error) return 'Erro desconhecido';
    if (typeof error === 'string') return error;
    if (error?.message) return error.message;
    if (error?.details) return error.details;
    try {
        return JSON.stringify(error);
    } catch {
        return 'Erro ao processar resposta do servidor';
    }
};

const AppContent: React.FC = () => {
  const supabase = useSupabase();

  const [session, setSession] = useState<Session | null>(null);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  const [currentPage, setCurrentPage] = useState<Page>('dashboard');

  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [theme, setTheme] = useState<Theme>('light');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isProfileLoading, setIsProfileLoading] = useState(false);
  const [dbSetupRequired, setDbSetupRequired] = useState(false);
  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const [confirmation, setConfirmation] = useState<{
    isOpen: boolean;
    message: string;
    onConfirm: () => void;
  }>({ isOpen: false, message: '', onConfirm: () => {} });

  const addToast = useCallback((message: string, type: ToastMessage['type'] = 'info') => {
    const id = Date.now().toString();
    setToasts(prev => [...prev, { id, message, type }]);
    setTimeout(() => {
      setToasts(currentToasts => currentToasts.filter(toast => toast.id !== id));
    }, 4000);
  }, []);

  const showConfirmation = useCallback((message: string, onConfirm: () => void) => {
    setConfirmation({
      isOpen: true,
      message,
      onConfirm: () => {
        onConfirm();
        setConfirmation({ isOpen: false, message: '', onConfirm: () => {} });
      },
    });
  }, []);

  const closeConfirmation = () => {
    setConfirmation({ isOpen: false, message: '', onConfirm: () => {} });
  };

  useEffect(() => {
    const initSession = async () => {
        try {
            const { data: { session }, error } = await supabase.auth.getSession();
            if (error) {
                if (error.message.includes('Refresh Token') || error.message.includes('refresh_token_not_found')) {
                    console.warn("Refresh token invalid or expired. Signing out to clear session.");
                    await supabase.auth.signOut();
                    setSession(null);
                } else {
                    console.error("Error retrieving session:", error);
                }
            } else {
                setSession(session);
            }
        } catch (e) {
            console.error("Unexpected error during session init:", e);
            setSession(null);
        }
    };
    initSession();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((event, session) => {
      if (event === 'SIGNED_OUT') {
          setSession(null);
          setCurrentUser(null);
      } else {
          setSession(session);
      }
    });

    return () => subscription.unsubscribe();
  }, [supabase]);

  useEffect(() => {
    const fetchUserProfile = async () => {
      if (session?.user) {
        setIsProfileLoading(true);

        const { error: checkError } = await supabase.from('organizations').select('id').limit(1);
        if (checkError && (checkError.code === '42P01' || checkError.code === 'PGRST205')) { 
            setDbSetupRequired(true);
            setIsProfileLoading(false);
            return;
        }

        const { data, error } = await supabase
          .from('profiles')
          .select('*')
          .eq('id', session.user.id)
          .single();

        if (data) {
          let finalOrgId = data.organization_id;

          if (!finalOrgId) {
             const { data: newOrgData, error: newOrgError } = await supabase
                  .from('organizations')
                  .insert({ name: 'Minha Empresa (Migrada)' })
                  .select();

             if (newOrgError) {
                 const errorMsg = getErrorMessage(newOrgError);
                 addToast(`Erro ao migrar conta: ${errorMsg}`, 'error');
             } else if (newOrgData && newOrgData.length > 0) {
                 finalOrgId = newOrgData[0].id;
                 await supabase.from('profiles').update({ organization_id: finalOrgId }).eq('id', session.user.id);
                 addToast('Seu perfil foi atualizado para a nova versão com Organizações.', 'success');
             }
          }

          setCurrentUser({
            id: data.id,
            name: data.full_name,
            email: session.user.email!,
            role: data.role as User['role'],
            organization_id: finalOrgId || undefined,
          });
        } else if (error && error.code === 'PGRST116') {
          let orgId: string | undefined;
          const inviteCode = localStorage.getItem('tempInviteCode');

          if (inviteCode) {
              const { data: orgData } = await supabase.from('organizations').select('id').eq('invite_code', inviteCode).single();
              if (orgData) {
                  orgId = orgData.id;
              } else {
                  addToast('Código de convite inválido. Criando nova empresa...', 'warning');
              }
              localStorage.removeItem('tempInviteCode');
          }

          if (!orgId) {
              const { data: newOrgData, error: newOrgError } = await supabase
                  .from('organizations')
                  .insert({ name: 'Minha Empresa' })
                  .select();

              if (newOrgData && newOrgData.length > 0) {
                  orgId = newOrgData[0].id;
              } else if (newOrgError) {
                  const errorMsg = getErrorMessage(newOrgError);
                  addToast(`Erro ao criar organização: ${errorMsg}`, 'error');
              }
          }

          if (orgId) {
              const { data: newProfile, error: insertError } = await supabase
                .from('profiles')
                .insert({
                  id: session.user.id,
                  full_name: session.user.email || 'Novo Usuário',
                  role: inviteCode ? 'stockist' : 'admin',
                  organization_id: orgId
                })
                .select()
                .single();

              if (insertError) {
                const errorMsg = getErrorMessage(insertError);
                addToast(`Erro ao criar perfil de usuário: ${errorMsg}`, 'error');
              } else if (newProfile) {
                setCurrentUser({
                  id: newProfile.id,
                  name: newProfile.full_name,
                  email: session.user.email!,
                  role: newProfile.role as User['role'],
                  organization_id: newProfile.organization_id || undefined,
                });
                addToast('Perfil de usuário criado com sucesso!', 'success');
              }
          }
        }
        setIsProfileLoading(false);
      } else {
        setCurrentUser(null);
      }
    };
    fetchUserProfile();
  }, [session, supabase, addToast]);


  const addActivityLog = useCallback(async (action: string) => {
    if (!currentUser) return;
    const newLog = {
      user: currentUser.name,
      action,
    };
     await supabase.from('activity_logs').insert(newLog);
  }, [currentUser, supabase]);


  const handleLogout = async () => {
    await addActivityLog('fez logout do sistema.');
    await supabase.auth.signOut();
  };

  useEffect(() => {
    const savedTheme = localStorage.getItem('theme') as Theme | null;
    const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
    const initialTheme = savedTheme || (prefersDark ? 'dark' : 'light');
    setTheme(initialTheme);
  }, []);

  useEffect(() => {
    const root = window.document.documentElement;
    root.classList.remove(theme === 'light' ? 'dark' : 'light');
    root.classList.add(theme);
    localStorage.setItem('theme', theme);
  }, [theme]);

  const renderPage = () => {
    if (!currentUser) return null;
    const commonProps = { addToast, showConfirmation, currentUser, addActivityLog };
    switch (currentPage) {
      case 'dashboard':
        return <Dashboard />;
      case 'stock':
        return <StockControl {...commonProps} />;
      case 'carParts':
        return <CarParts {...commonProps} />;
      case 'suppliers':
        return <Suppliers {...commonProps} />;
      case 'clients':
        return <Clients {...commonProps} />;
      case 'employees':
        return <Employees {...commonProps} />;
      case 'users':
        return <Users {...commonProps} />;
      case 'assets':
        return <Assets {...commonProps} />;
      case 'categories':
        return <Categories {...commonProps} />;
       case 'nfcontrol':
        return <NFControl />;
      case 'reports':
        return <Reports />;
      case 'quotes':
