export interface SerproData {
  nome: string;
  birthDate?: string;
  logradouro?: string;
  numero?: string;
  complemento?: string;
  bairro?: string;
  cidade?: string;
  uf?: string;
  cep?: string;
  situacaoCadastral?: string;
}

export const consultarCPF = async (cpf: string, supabase: SupabaseClient): Promise<SerproData> => {
  const cleanCPF = cpf.replace(/\D/g, '');

  if (cleanCPF.length !== 11) {
    throw new Error("CPF inválido. Deve conter 11 dígitos.");
  }

  try {
    const { data, error } = await supabase.functions.invoke('serpro-consulta', {
      body: { cpf: cleanCPF }
    });

    if (error) {
      console.error("Erro na Edge Function:", error);

      // Clearer messaging for the common "Failed to fetch" error when function is not deployed
      if (error instanceof TypeError || error.message?.includes('Failed to fetch')) {
          throw new Error('Não foi possível conectar à função do servidor. Verifique se a Edge Function "serpro-consulta" foi publicada no seu projeto Supabase.');
      }

      throw new Error(`Erro na consulta: ${error.message || 'Desconhecido'}`);
    }

    if (!data || data.error) {
       throw new Error(data?.error || "O servidor não retornou dados válidos.");
    }

    // Process results
    let situacaoDescricao = 'DESCONHECIDO';
    if (data.situacao) {
        situacaoDescricao = typeof data.situacao === 'object' ? data.situacao.descricao : data.situacao;
    }

    let birthDate = undefined;
    const rawNasc = data.nascimento || data.dataNascimento;
    if (rawNasc) {
        const rawDate = String(rawNasc).replace(/\D/g, '');
        if (rawDate.length === 8) {
            const day = rawDate.substring(0, 2);
            const month = rawDate.substring(2, 4);
            const year = rawDate.substring(4);
            birthDate = `${year}-${month}-${day}`;
        }
    }

    const src = data.domicilio_fiscal || data.endereco || data;

    return {
      nome: data.nome || data.ni || "Nome não identificado",
      birthDate: birthDate,
      logradouro: src.logradouro || '',
      numero: src.numero || '',
      complemento: src.complemento || '',
      bairro: src.bairro || '',
      cidade: src.cidade || src.municipio || '',
      uf: src.uf || src.estado || '',
      cep: src.cep || '',
      situacaoCadastral: situacaoDescricao
    };

  } catch (err: any) {
    console.error("Falha na consulta SERPRO:", err);
    throw new Error(err.message || "Falha ao consultar base de dados externa.");
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { Product, StockMovement, ParsedNFe } from '../types';

/**
 * World-class senior frontend engineer implementation for Gemini API.
 * Adhering to strict coding guidelines:
 * 1. Initialize with named parameter { apiKey: process.env.API_KEY }.
 * 2. Use Gemini 3 series models for better reasoning and parsing.
 * 3. Access response text via the .text property.
 */

export const getStockAnalysis = async (
  prompt: string,
  products: Product[],
  movements: StockMovement[]
): Promise<string> => {
  // Use the mandatory initialization pattern
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Use Gemini 3 for complex reasoning tasks
  const model = 'gemini-3-flash-preview';

  const systemInstruction = `Você é um assistente especialista em análise de estoque para uma oficina ou pequena indústria. Sua tarefa é analisar os dados de estoque e movimentações em formato JSON e responder à pergunta do usuário de forma clara, concisa e em português.
  - Dados de Produtos: Lista de produtos com ID, nome, quantidade atual, preço unitário e estoque mínimo.
  - Dados de Movimentações: Histórico de entradas e saídas.
  - Para perguntas de previsão (ex: "quando o produto X vai acabar?"), analise o histórico de saídas ('out') para calcular um consumo médio diário ou mensal e faça uma projeção. Deixe claro que é uma estimativa.
  - Forneça insights úteis, diretos e baseados nos dados fornecidos.`;

  const simplifiedProducts = products.slice(0, 50).map(p => ({
      name: p.name,
      qty: p.quantity,
      price: p.unit_price,
      min: p.min_stock
  }));

  const simplifiedMovements = movements
    .filter(m => new Date(m.date) > new Date(Date.now() - 90 * 24 * 60 * 60 * 1000))
    .slice(0, 20)
    .map(m => ({
        prod: m.product_name,
        type: m.type,
        qty: m.quantity,
        date: m.date ? m.date.split('T')[0] : 'N/A'
    }));

  const fullPrompt = `
    Aqui estão os dados atuais do estoque (resumidos):
    Produtos (Amostra):
    ${JSON.stringify(simplifiedProducts)}

    Movimentações de Estoque (Recentes):
    ${JSON.stringify(simplifiedMovements)}

    Pergunta do Usuário: "${prompt}"

    Sua análise:
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: [{ role: 'user', parts: [{ text: fullPrompt }] }],
      config: {
          systemInstruction: systemInstruction,
          temperature: 0.5,
      }
    });

    if (!response || !response.text) {
        return "A IA processou a solicitação mas não retornou texto. Tente reformular a pergunta.";
    }

    return response.text;
  } catch (error: any) {
    console.error("Error calling Gemini API:", error);

    // Specifically handle the "Failed to fetch" error for better user feedback
    if (error.message?.includes("Failed to fetch") || error.name === "TypeError") {
        return "Erro de Conexão: Não foi possível alcançar o serviço do Google Gemini. Verifique sua conexão com a internet ou se a API Key é válida.";
    }

    return `Erro ao consultar IA: ${error.message || "Falha na comunicação com o servidor Gemini."}`;
  }
};

export const parseInvoicePDF = async (pdfBase64: string): Promise<ParsedNFe> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-3-flash-preview';

    const prompt = "Analise o documento PDF anexado (Nota Fiscal) e extraia os dados do fornecedor e os itens da nota. Retorne estritamente em JSON.";

    const pdfPart = {
        inlineData: {
            mimeType: 'application/pdf',
            data: pdfBase64,
        },
    };

    try {
        const response = await ai.models.generateContent({
            model: model,
            contents: { parts: [{ text: prompt }, pdfPart] },
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        supplier: {
                            type: Type.OBJECT,
                            properties: {
                                name: { type: Type.STRING },
                                cnpj: { type: Type.STRING },
                            },
                            required: ["name", "cnpj"]
                        },
                        products: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    code: { type: Type.STRING },
                                    name: { type: Type.STRING },
                                    quantity: { type: Type.NUMBER },
                                    unit_price: { type: Type.NUMBER },
                                },
                                required: ["code", "name", "quantity", "unit_price"]
                            }
                        }
                    },
                    required: ["supplier", "products"]
                }
            },
        });

        if (!response.text) throw new Error("A IA retornou uma resposta vazia.");

        return JSON.parse(response.text) as ParsedNFe;

    } catch (error: any) {
        console.error("Error parsing PDF invoice:", error);
        if (error.message?.includes("Failed to fetch")) {
            throw new Error("Erro de conexão ao enviar o PDF para processamento pela IA.");
        }
        throw new Error(`Erro ao analisar PDF: ${error.message || "Falha na comunicação."}`);
    }
};

